"""Demand service — generates trip requests per tick."""

from __future__ import annotations

import random
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import TYPE_CHECKING

from app.core.city import Station

if TYPE_CHECKING:
    from app.core.satisfaction import SatisfactionTracker
    from app.models.npc import NpcPopulation


@dataclass
class TripRequest:
    """A single trip demand generated by the simulation."""

    from_station: str
    to_station: str
    bike_id: str | None = None
    distance_km: float = 0.0  # populated by TripExecutor on assignment


class TripGenerator(ABC):
    """Abstract interface for trip-request generators."""

    @abstractmethod
    def generate(
        self, tick: int, stations: dict[str, Station]
    ) -> list[TripRequest]:
        """Return trip requests for the given tick and available stations."""
        ...


class DemandService(TripGenerator):
    """Generates NPC trip demand based on time-of-day patterns."""

    def generate(
        self, tick: int, stations: dict[str, Station]
    ) -> list[TripRequest]:
        """Return trip requests for the given tick.

        Phase 1: stub returning empty list.
        Phase 2+: real commuter-tide generation.
        """
        _ = tick, stations
        return []


# ── reference price for elasticity calculation ──────────────────

_REFERENCE_PRICE_PER_30MIN = 1.5  # "标准" tier price


class RuleBasedDemandService(TripGenerator):
    """Minimal viable trip generator — good enough for v0.2.

    Generates trips using simple time-of-day heuristics:
    - Peak hours (7-9am, 5-7pm): higher trip rate
    - Off-peak hours: lower trip rate
    - Random OD pairs across available stations

    Supports **price elasticity**: higher prices reduce trip demand,
    lower prices increase it. This makes pricing a meaningful trade-off
    rather than a cosmetic choice.
    """

    def __init__(
        self,
        base_rate: float = 0.02,
        peak_rate: float = 0.08,
        price_elasticity: float = -0.3,
        reference_price: float = _REFERENCE_PRICE_PER_30MIN,
    ) -> None:
        self.base_rate = base_rate
        self.peak_rate = peak_rate
        self.price_elasticity = price_elasticity
        self.reference_price = reference_price

    def generate(
        self, tick: int, stations: dict[str, Station],
    ) -> list[TripRequest]:
        if not stations:
            return []

        hour = (tick % 1440) // 60
        is_peak = (7 <= hour <= 9) or (17 <= hour <= 19)
        rate = self.peak_rate if is_peak else self.base_rate
        rate = max(0.0, rate)

        n_trips = max(1, int(len(stations) * rate * random.uniform(0.8, 1.2)))

        station_ids = list(stations.keys())
        from_ids = random.choices(station_ids, k=n_trips)
        to_ids = random.choices(station_ids, k=n_trips)
        return [
            TripRequest(from_station=f, to_station=t)
            for f, t in zip(from_ids, to_ids)
            if f != t  # skip self-loops
        ]

    def effective_rate(self, base_rate: float, current_price: float) -> float:
        """Apply price elasticity to the base demand rate.

        Formula:
            effective_rate = base_rate × (1 + elasticity × (price / reference_price - 1))

        With elasticity = -0.3:
        - price = 1.0 (亲民): rate × (1 - 0.3 × (1.0/1.5 - 1)) = rate × 1.10  (+10%)
        - price = 1.5 (标准): rate × (1 - 0.3 × (1.5/1.5 - 1)) = rate × 1.00  (baseline)
        - price = 2.5 (高端): rate × (1 - 0.3 × (2.5/1.5 - 1)) = rate × 0.80  (-20%)
        """
        if self.reference_price <= 0 or self.price_elasticity == 0:
            return base_rate
        ratio = current_price / self.reference_price
        elastic_factor = 1.0 + self.price_elasticity * (ratio - 1.0)
        return base_rate * max(0.0, elastic_factor)


class CommuteDemandService(TripGenerator):
    """NPC commute-aware trip generator — replaces RuleBasedDemandService as default.

    Phase D (v0.4): Uses NPC population to generate realistic commute trips:
    - Morning peak (06:00-08:00): NPCs travel home → work
    - Evening peak (17:00-19:00): NPCs travel work → home
    - Off-peak: random short leisure/errand trips with lower rate
    - Price elasticity: higher prices reduce demand, lower prices increase it

    Satisfaction feedback: stations with low satisfaction generate fewer trips.
    """

    def __init__(
        self,
        population: NpcPopulation | None = None,
        satisfaction_tracker: SatisfactionTracker | None = None,
        base_leisure_rate: float = 0.01,
        peak_leisure_rate: float = 0.03,
        price_elasticity: float = -0.3,
        reference_price: float = 1.5,
    ) -> None:
        self.population = population
        self.satisfaction_tracker = satisfaction_tracker
        self.base_leisure_rate = base_leisure_rate
        self.peak_leisure_rate = peak_leisure_rate
        self.price_elasticity = price_elasticity
        self.reference_price = reference_price

    def generate(
        self, tick: int, stations: dict[str, Station],
    ) -> list[TripRequest]:
        if not stations:
            return []

        trips: list[TripRequest] = []
        now = tick % 1440
        hour = now // 60

        # ── 1. Commute trips from NPC population ─────────────────
        if self.population is not None:
            for npc in self.population.npcs:
                from_s, to_s = npc.trip_od(tick, stations)
                if from_s and to_s and from_s in stations and to_s in stations:
                    # Apply satisfaction factor
                    factor = 1.0
                    if self.satisfaction_tracker is not None:
                        factor = self.satisfaction_tracker.get_demand_factor(from_s)
                    if random.random() < factor:
                        trips.append(TripRequest(from_station=from_s, to_station=to_s))

        # ── 2. Leisure/errand trips (off-peak random trips) ──────
        is_peak = (6 <= hour <= 9) or (17 <= hour <= 19)
        leisure_rate = self.peak_leisure_rate if is_peak else self.base_leisure_rate

        # Scale leisure trips by number of stations (fewer during peak commute)
        n_leisure = max(0, int(len(stations) * leisure_rate * random.uniform(0.5, 1.0)))

        if n_leisure > 0:
            station_ids = list(stations.keys())
            for _ in range(n_leisure):
                from_s = random.choice(station_ids)
                to_s = random.choice([s for s in station_ids if s != from_s])

                # Apply satisfaction factor at origin
                factor = 1.0
                if self.satisfaction_tracker is not None:
                    factor = self.satisfaction_tracker.get_demand_factor(from_s)
                if random.random() < factor:
                    trips.append(TripRequest(from_station=from_s, to_station=to_s))

        return trips
